    for dx, dy in dirs:
        nx, ny = sx + dx, sy + dy
        if not valid(nx, ny):
            continue
        if resources:
            md = 10**18
            min_op = 10**18
            for rx, ry in resources:
                d = abs(rx - nx) + abs(ry - ny)
                if d < md:
                    md = d
            min_op = abs(ox - nx) + abs(oy - ny)
            score = -md * 10 - min_op
